+            prop_assert!(
+                b.p50_us <= b.p95_us + 1e-6,
+                "{}: p50={} > p95={}", b.stage, b.p50_us, b.p95_us
+            );
+            prop_assert!(
+                b.p95_us <= b.p99_us + 1e-6,
+                "{}: p95={} > p99={}", b.stage, b.p95_us, b.p99_us
+            );
+            prop_assert!(
+                b.p99_us <= b.p999_us + 1e-6,
+                "{}: p99={} > p999={}", b.stage, b.p99_us, b.p999_us
+            );
+        }
+    }
